# Arabic normalization utilities

AR_DIACRITICS = ''.join(chr(c) for c in range(0x064B, 0x065F+1)) + '\u0670' + '\u0640'  # tashkeel + tatweel + superscript alif
AR_DIACRITICS_SET = set(AR_DIACRITICS)

punct_pattern = re.compile(r'[^\w\s\u0600-\u06FF]+', flags=re.UNICODE)

def strip_diacritics(text):
    # Remove Tashkeel and tatweel and arabic superscript alif
    return ''.join(ch for ch in text if ch not in AR_DIACRITICS_SET)

def normalize_hamza(text):
    # unify hamza forms: alif with hamza above/below to bare alif; yah with hamza to yah; waw hamza to waw, etc.
    replacements = {
        'أ':'ا', 'إ':'ا', 'آ':'ا',
        'ؤ':'و', 'ئ':'ي', 'ء':'ء',
        'ة':'ه',  # maybe unify ta marbuta to ha for search? Not always recommended, but helps broad search.
        'ى':'ي',  # alef maqsura to ya
    }
    return ''.join(replacements.get(ch, ch) for ch in text)

def normalize_arabic(text):
    if not isinstance(text, str):
        return ''
    t = strip_diacritics(text)
    t = normalize_hamza(t)
    # remove punctuation
    t = punct_pattern.sub(' ', t)
    # collapse whitespace
    t = re.sub(r'\s+', ' ', t).strip()
    return t.lower()

def lcs_length(a, b):
    # Longest common subsequence length
    n, m = len(a), len(b)
    # optimize space if needed
    dp = [0]*(m+1)
    for i in range(1, n+1):
        prev = 0
        for j in range(1, m+1):
            tmp = dp[j]
            if a[i-1] == b[j-1]:
                dp[j] = prev + 1
            else:
                dp[j] = max(dp[j], dp[j-1])
            prev = tmp
    return dp[m]

def normalized_lcs_ratio(s1, s2):
    # Use normalized (by length) LCS ratio: 2*LCS/(len1+len2)
    if not s1 or not s2:
        return 0.0
    a = normalize_arabic(s1)
    b = normalize_arabic(s2)
    if not a or not b:
        return 0.0
    lcs = lcs_length(a, b)
    return (2.0*lcs)/(len(a)+len(b))

def token_f1(s1, s2):
    a = normalize_arabic(s1).split()
    b = normalize_arabic(s2).split()
    ca = Counter(a)
    cb = Counter(b)
    # compute overlap multiset
    overlap = 0
    for k in set(ca.keys()) | set(cb.keys()):
        overlap += min(ca[k], cb[k])
    prec = overlap / (sum(cb.values()) + 1e-9)
    rec = overlap / (sum(ca.values()) + 1e-9)
    if prec+rec == 0:
        return 0.0
    return 2*prec*rec/(prec+rec)

